insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('15827', 'cer.dik', 'cerdik', '', '', '["Adjektiva","Adjektiva"]', '[{"nomor":"1","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"Cepat mengerti tentang situasi dan pandai mencari pemecahannya; panjang akal; banyak akal.","contoh":[{"nomor":1,"teks":"Anak itu sangat cerdik, ia bisa menyelesaikan teka-teki sulit dalam hitungan menit."},{"nomor":2,"teks":"Jika jadi pedagang, selain harus pandai berdagang, harus cerdik pula."},{"nomor":3,"teks":"Dengan kecerdikannya, ia mampu menemukan cara baru untuk menghemat biaya produksi."}]},{"nomor":"2","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"Banyak tipu muslihatnya; licik; licin.","contoh":[{"nomor":1,"teks":"Pencuri itu sangat cerdik hingga sulit ditangkap oleh polisi."},{"nomor":2,"teks":"Dia seorang penipu yang cerdik, lima kali berhasil lolos dari penangkapan polisi."},{"nomor":3,"teks":"Dengan cara yang cerdik, ia berhasil mengelabui lawannya."}]}]', null, '["kecerdikan","secerdik","tercerdik"]', '["cerdik buruk","cerdik busuk","cerdik cendekia","cerdik pandai"]', '["biar miskin asal cerdik, terlawan jua orang kaya","bingung tak dapat diajar, cerdik tak dapat diikuti","cerdik membilang kawan","gemuk membuang lemak, cerdik membuang kawan","pergi tempat bertanya, pulang tempat berberita (berkenaan dengan orang cerdik pandai)","siapa cerdik tinggi naik, siapa calak menang berhitung"]', '[]', '[{"peribahasa":"biar miskin asal cerdik, terlawan jua orang kaya","makna":"Kecerdasan dan kebijaksanaan lebih utama daripada kekayaan; orang cerdas dapat menandingi atau mengalahkan orang kaya yang kurang bijak."},{"peribahasa":"bingung tak dapat diajar, cerdik tak dapat diikuti","makna":"Orang yang bingung sulit untuk diajari, sedangkan orang yang terlalu cerdik terkadang sulit untuk diikuti cara atau pikirannya."},{"peribahasa":"cerdik membilang kawan","makna":"Orang yang pandai memilih teman yang baik dan bermanfaat baginya."},{"peribahasa":"gemuk membuang lemak, cerdik membuang kawan","makna":"Orang yang terlalu percaya diri atau merasa cukup sering mengabaikan bantuan atau dukungan orang lain."},{"peribahasa":"pergi tempat bertanya, pulang tempat berberita (berkenaan dengan orang cerdik pandai)","makna":"Orang yang berilmu menjadi tempat bertanya dan juga sumber informasi bagi orang lain."},{"peribahasa":"siapa cerdik tinggi naik, siapa calak menang berhitung","makna":"Orang yang cerdas akan mendapat kedudukan tinggi, sedangkan orang yang mahir dalam perhitungan akan menang atau berhasil dalam urusan."}]');
