insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('16168', 'cin.cin', 'cincin', '', '', '["Nomina","Nomina","Nomina","Kimia","Nomina","Kimia"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"Perhiasan berupa lingkaran kecil yang dipakai di jari, ada yang berpermata, ada yang tidak.","contoh":[{"nomor":1,"teks":"Dia mengenakan cincin emas warisan ibunya."},{"nomor":2,"teks":"Cincin berlian itu memantulkan cahaya indah di bawah sinar lampu."},{"nomor":3,"teks":"Ia membeli cincin polos untuk lamaran."}]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"Segala sesuatu yang berbentuk lingkaran (seperti gelang-gelang kecil pada tombak atau mata rantai).","contoh":[{"nomor":1,"teks":"Cincin logam itu menghubungkan dua rantai besi."},{"nomor":2,"teks":"Pancing itu dilengkapi cincin kecil untuk mengaitkan tali."},{"nomor":3,"teks":"Gerbang dihiasi dengan cincin besi sebagai ornamen."}]},{"nomor":"3","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"Kim","nama":"Kimia","tipe":"bidang_subjek"}],"definisi":"Sekelompok atom yang dihubungkan oleh ikatan-ikatan yang dapat direpresentasikan secara grafis dalam bentuk poligonal; rantai tertutup.","contoh":[{"nomor":1,"teks":"Cincin benzena memiliki enam atom karbon."},{"nomor":2,"teks":"Struktur cincin pada senyawa ini membuatnya stabil."},{"nomor":3,"teks":"Dalam kimia organik, cincin aromatik sering ditemukan pada senyawa alami."}]},{"nomor":"4","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"Kim","nama":"Kimia","tipe":"bidang_subjek"}],"definisi":"Susunan atom yang direpresentasikan dalam rumus atau model dalam bentuk siklus.","contoh":[{"nomor":1,"teks":"Senyawa ini memiliki dua cincin yang terhubung."},{"nomor":2,"teks":"Model 3D memperlihatkan cincin sikloheksana."},{"nomor":3,"teks":"Cincin dalam struktur senyawa menentukan sifat kimianya."}]}]', null, '[]', '["cincin anye","cincin api Pasifik","cincin aromatik","cincin bawang bombai","cincin belah rotan","cincin benzena","cincin berapit","cincin Cabot","cincin cap","cincin delima","cincin hidung","cincin juara","cincin karbon","cincin kasali","cincin kawin","cincin Kayser-Fleischer","cincin lamaran","cincin mata","cincin meterai","cincin mohor","cincin nikah","cincin pegas","cincin penyetel","cincin pertunangan","cincin pintal tiga","cincin polos","cincin rantai","cincin roh","cincin saraf","cincin Saturnus","cincin sebentuk","cincin solitaire","cincin stempel","cincin talipuk","cincin torak","cincin tunang","cincin ular","cincin uskup","cincin vagina","cincin Waldeyer"]', '["bagai si kudung beroleh cincin","kalau kena tampar, biar dengan tangan yang pakai cincin, kalau kena tendang, biar dengan kaki yang pakai kasut","seidas bagai benang, sebentuk bagai cincin","seperti cincin dengan permata"]', '[]', '[{"peribahasa":"bagai si kudung beroleh cincin","makna":"Mendapat suatu keuntungan atau pemberian, tetapi tidak dapat memanfaatkannya."},{"peribahasa":"kalau kena tampar, biar dengan tangan yang pakai cincin, kalau kena tendang, biar dengan kaki yang pakai kasut","makna":"Jika harus menerima hukuman, lebih baik dari orang yang berkuasa atau terhormat daripada dari orang rendahan."},{"peribahasa":"seidas bagai benang, sebentuk bagai cincin","makna":"Sangat cocok dan serasi satu sama lain."},{"peribahasa":"seperti cincin dengan permata","makna":"Dua hal atau orang yang sangat serasi dan saling melengkapi."}]');
